sql:
SELECT city, state, elevation, start_date, end_date
FROM stations
INNER JOIN station_data ON stations.station_id = station_data.station_id;

SELECT stations.station_id, stations.city
FROM stations
JOIN station_files ON stations.station_id = station_files.station_id;

SELECT station_id, COUNT(DISTINCT data_id) AS Unique_Data_Entries
FROM station_data
GROUP BY station_id;

SELECT station_id, start_date, end_date, data_type
FROM station_data
WHERE data_id = 130;

SELECT note_id, note
FROM station_notes
WHERE note_type = 'maintenance' AND note_date > '2022-01-01';

SELECT station_id, COUNT(DISTINCT data_type) AS number_of_unique_data_types
FROM station_data
GROUP BY station_id;

SELECT COUNT(*)
FROM station_files
WHERE file_type = 'DOCX';

SELECT *
FROM station_images
WHERE station_id = 1;

SELECT * 
FROM data_comments 
WHERE comment_type = 'error report';

